module top_module(
    A,
    B,
    OPCODE,
    RESET,
    RESULT
);input [31:0] A;
    input [31:0] B;
    input [1:0] OPCODE;
    input RESET;
    output [31:0] RESULT;

    reg [31:0] calc_result;

    always @(*) begin
        case(OPCODE)
            2'b00: calc_result = A + B; // addition
            2'b01: calc_result = A - B; // subtraction
            2'b10: calc_result = A * B; // multiplication
            2'b11: calc_result = A / B; // division
            default: calc_result = 0; // default case
        endcase

        if(RESET) begin
            calc_result = 0; // reset calc_result to 0
        end
    end

    assign RESULT = calc_result;

endmodule
